#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N], B[N], C[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d %d", &A[i], &B[i], &C[i]);
        }
        int max_size = 0;
        for (int mask = 0; mask < (1 << N); mask++) {
            int size = 0;
            int is_perfect = 1;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i))) {
                    size++;
                    for (int j = i + 1; j < N; j++) {
                        if ((mask & (1 << j))) {
                            if (A[i] * B[j] - A[j] * B[i] == 0 && A[i] * C[j] - A[j] * C[i] == 0 && B[i] * C[j] - B[j] * C[i] == 0) {
                                is_perfect = 0;
                                break;
                            }
                        }
                    }
                    if (!is_perfect) break;
                }
            }
            if (is_perfect) max_size = (max_size > size) ? max_size : size;
        }
        printf("%d\n", max_size);
    }
    return 0;
}

