        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            int[] C = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
                B[i] = sc.nextInt();
                C[i] = sc.nextInt();
            }
            int max_size = 0;
            for (int mask = 0; mask < (1 << N); mask++) {
                int size = 0;
                int is_perfect = 1;
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) != 0) {
                        size++;
                        for (int j = i + 1; j < N; j++) {
                            if ((mask & (1 << j)) != 0) {
                                if (A[i] * B[j] - A[j] * B[i] == 0 && A[i] * C[j] - A[j] * C[i] == 0 && B[i] * C[j] - B[j] * C[i] == 0) {
                                    is_perfect = 0;
                                    break;
                                }
                            }
                        }
                        if (is_perfect == 0) break;
                    }
                }
                if (is_perfect) max_size = Math.max(max_size, size);
            }
            System.out.println(max_size);
        }
    }
}

